import requests
import time

API_URL = "http://api.openweathermap.org/data/2.5/weather?q={city}&appid={api_key}"
API_KEY = "YOUR_API_KEY"  # Replace with your real API key

def get_weather(city, retries=3, backoff=30):
    params = {"q": city, "appid": API_KEY}
    for attempt in range(retries + 1):
        try:
            resp = requests.get(API_URL.format(**params))
            resp.raise_for_status()
            return resp.json()
        except requests.exceptions.HTTPError as e:
            if 400 <= e.response.status_code < 600:
                continue
            raise
        except Exception as e:
            if attempt == retries:
                raise
            print(f"Attempt {attempt + 1}/{retries} failed: {e}")
            time.sleep(backoff)
            backoff *= 2
    return None

if __name__ == "__main__":
    city = input("Enter city: ")
    try:
        weather = get_weather(city)
        if weather:
            print(f"Weather for {city}: {weather['weather'][0]['main']}")
        else:
            print("Failed to fetch weather data.")
    except Exception as e:
        print(f"An error occurred: {e}")
```

